  List getDetailsFromDB(Connection conn, String table) {
    List detailsAsList = new ArrayList();
    Statement stmt = null;
    try {
      stmt = conn.createStatement();
      String sql = "SELECT SETID_LOCATION,DESCR FROM " + table;
      ResultSet rs = stmt.executeQuery(sql);

      while(rs.next()){
        String location = rs.getString("SETID_LOCATION");
        String description = rs.getString("DESCR");
        detailsAsList.add(location + "|" + description);
      }
      rs.close();
      stmt.close();
    } catch(SQLException se){
      logger.error("Exception in reading from database: "+se.getMessage());
    }catch(Exception e){
      logger.error("Exception in reading from database: "+e.getMessage());
    }finally{
      try{
        if(stmt!=null)
          stmt.close();
      }catch(SQLException se2){
        logger.error("Exception in closing database connection: "+se2.getMessage());
      }
    }

    return detailsAsList;
  }

  List getVendorListFromFile(String filePath) {
    FileReader fileReader = null;
    BufferedReader br = null;
    List fileAsList = new ArrayList();
    try {
      fileReader = new FileReader(filePath);    
      br = new BufferedReader(fileReader);    
      //skipping header
      br.readLine();

      line = br.readLine();
      while(line != null){
        List eachRow = Util.csvToList(line);
        if (eachRow != null && eachRow.size() == 2) {
          String value = eachRow.get(0) + "|" + eachRow.get(1);
          fileAsList.add(value);
        }
        line = br.readLine();
      }
      br.close();
      fileReader.close();
    }
    catch (IOException ioe) {
      logger.error("Exception in reading from file: "+ioe.getMessage());
    }
    finally {
      try {	
        if (br != null) 
          br.close();
        if (fileReader != null)
          fileReader.close();
      } catch (IOException ioe2) {
        logger.error("Exception in closing file connection: "+ioe2.getMessage());
      }
    }
    return fileAsList;
  }

  Map getDetailsFromDatabase(Connection conn) {
    Map resultMap = new HashMap();
    List jobCodeList = new ArrayList();
    List locationList = new ArrayList();
    List departmentList = new ArrayList();
    List vendorList = new ArrayList();

    Statement stmt = null;
    ResultSet rs = null;
    try {

      stmt = conn.createStatement();
      rs = stmt.executeQuery(SQL_QUERY);
      while(rs.next()){
        String location = rs.getString("SETID_LOCATION");
        String description = rs.getString("DESCR");
        String tableName = rs.getString("TABLE_NAME");
        if (Util.isNotNullOrEmpty(tableName) && tableName.equalsIgnoreCase(JOB_CODE_TABLE)) {
          jobCodeList.add(location + "|" + description);
        } else if (Util.isNotNullOrEmpty(tableName) && tableName.equalsIgnoreCase(DEPT_TABLE)) {
          departmentList.add(location + "|" + description);
        } else if (Util.isNotNullOrEmpty(tableName) && tableName.equalsIgnoreCase(LOCATION_TABLE)) {
          locationList.add(location + "|" + description);
        } else if (Util.isNotNullOrEmpty(tableName) && tableName.equalsIgnoreCase(VENDOR_TABLE)) {
          vendorList.add(location + "|" + description);
        }
      }

      rs.close();
      stmt.close();

    } catch (SQLException se) {
      logger.error("Exception in reading from database: "+se.getMessage());
    } finally {
      try  {
        if (rs != null) {
          rs.close();
        }
        if (stmt != null) {
          stmt.close();
        }
      } catch (SQLException se2) {
        logger.error("Exception in closing database connection: "+se2.getMessage());
      }
    }
    resultMap.put(JOB_CODE_TABLE, jobCodeList);
    resultMap.put(DEPT_TABLE, departmentList);
    resultMap.put(LOCATION_TABLE, locationList);
    resultMap.put(VENDOR_TABLE, vendorList);
    return resultMap;
  }

  void insertIntoDB(Connection conn, List valueList, String tableName) {
    PreparedStatement insertStatement = null;

    try {
      insertStatement = conn.prepareStatement("INSERT INTO " + tableName + " VALUES (?, ?)"); 
      for (String newRow : valueList) {
        String[] values = newRow.split("\\|");
        if (values != null && values.length == 2)
        {
          insertStatement.setString(2, values[1]);
          insertStatement.setString(1, values[0]);

          insertStatement.executeUpdate();
        }
      }
      insertStatement.close();
    }catch(SQLException se){
      logger.error("Exception in writing to database: "+se.getMessage());
    }catch(Exception e){
      logger.error("Exception in writing to database: "+e.getMessage());
    }finally{
      try{
        if(insertStatement!=null)
          insertStatement.close();
      }catch(SQLException se2){
        logger.error("Exception in closing database connection: "+se2.getMessage());
      }
    }
  }


  String getDBInteraction(String query, String tableCol) {
    String dbValue = "";
    Connection conn = context.getJdbcConnection();
    Statement stmt = null;
    ResultSet rs = null;

    try {
      stmt = conn.createStatement();
      rs = stmt.executeQuery(query);
      while(rs.next()){
        dbValue = rs.getString(tableCol);       
      }
      stmt.close();
      rs.close();
    } catch(SQLException se){
      logger.error("Exception in reading from database: "+se.getMessage());
    }catch(Exception e){
      logger.error("Exception in reading from database: "+e.getMessage());
    }finally{
      try {
        if (stmt != null){	stmt.close();	}
        if (rs != null){	rs.close();	}
      } catch (SQLException se) {
        logger.error("Exception in database Operation : " + se.getMessage());
      }
    }
    return dbValue;
  }


  String getStreetAddress(String colValue){

    String sqlQuery = "SELECT Address_1 FROM LOCATIONS WHERE LOCATION_NAME='"+colValue+"'";
    String dbValue = getDBInteraction(sqlQuery,"Address_1");

