  public Map getManagerMapFromDB() {
    logger.debug("Entering getManagerMapFromDB");
    Map result = new HashMap();
    Statement stmt = null;
    ResultSet rs = null;
    Connection conn = null;
    String query = "SELECT Empl_ID,fname_lname FROM ManagerNameToID where fname_lname != '' and Empl_ID != ''";
    try {
      conn = context.getJdbcConnection();
      if(conn!=null){
        stmt = conn.createStatement();
        rs = stmt.executeQuery(query);
        while (rs!=null && rs.next()) {
          result.put(rs.getString("fname_lname"), rs.getString("Empl_ID"));
        }
        stmt.close();
        rs.close();
        conn.close();
      }
    } catch (SQLException se) {
      logger.error("Exception in ManagerMapFromDB from database: " + se.getMessage());
    } catch (Exception e) {
      logger.error("Exception in ManagerMapFromDB from database: " + e.getMessage());
    } finally {
      try {
        if (stmt != null){	stmt.close();	}
        if (rs != null){	rs.close();	}
        if (conn != null){	conn.close();	}
      } catch (SQLException se) {
        logger.error("Exception in database Operation : " + se.getMessage());
      }
    }
    logger.debug("Entering getManagerMapFromDB");
    return result;
  }


