  String SQL_QUERY = "SELECT SETID_LOCATION,DESCR,'ps_ahhr_sailp_jc_v' AS TABLE_NAME FROM ps_ahhr_sailp_jc_v UNION SELECT SETID_LOCATION,DESCR,'ps_ahhr_sailp_l_vw' AS TABLE_NAME FROM ps_ahhr_sailp_l_vw UNION SELECT SETID_LOCATION,DESCR,'ps_ahhr_sailp_d_vw' AS TABLE_NAME FROM ps_ahhr_sailp_d_vw UNION SELECT 'AMITA' AS SETID_LOCATION,Location_Name,'ps_ahhr_sailp_l_vw' AS TABLE_NAME FROM Locations UNION SELECT 'AMITA' AS SETID_LOCATION,Job_Title_Description,'ps_ahhr_sailp_jc_v' AS TABLE_NAME FROM JobCodes UNION SELECT 'AMITA' AS SETID_LOCATION,DESCR,'ps_ahhr_sailp_jc_v' AS TABLE_NAME FROM ps_ahhr_sailp_jc_v UNION SELECT 'AMITA' AS SETID_LOCATION,Organization,'ps_ahhr_sailp_v_vw' AS TABLE_NAME FROM Vendors UNION SELECT 'AMITA' AS SETID_LOCATION,DESCR,'ps_ahhr_sailp_d_vw' AS TABLE_NAME FROM ps_ahhr_sailp_d_vw WHERE SETID_LOCATION='ILARL'";

  String JOB_CODE_TABLE = "ps_ahhr_sailp_jc_v";
  String DEPT_TABLE = "ps_ahhr_sailp_d_vw";
  String LOCATION_TABLE = "ps_ahhr_sailp_l_vw";
  String VENDOR_TABLE = "ps_ahhr_sailp_v_vw";
